package com.santiago.soberpath.domain.model
import java.time.LocalDate
// Daily pledge and emotional log. data class DailyCheckIn( val id: String, val habitId: String, val date: LocalDate, val mood: String, val cravingLevel: Int, val note: String?, val completedPledge: Boolean )

package com.santiago.soberpath.domain.model
import java.time.LocalDate
// Core habit tracked by the app. data class Habit( val id: String, val name: String, val category: String, val startDate: LocalDate, val lastRelapseDate: LocalDate, val dailyCost: Double, val currency: String, val isActive: Boolean )

package com.santiago.soberpath.domain.model
import java.time.LocalDateTime
// Personal motivation to stay on track. data class MotivationReason( val id: String, val habitId: String, val text: String, val createdAt: LocalDateTime )

package com.santiago.soberpath.domain.repository
import com.santiago.soberpath.domain.model.DailyCheckIn import kotlinx.coroutines.flow.Flow
interface CheckInRepository { suspend fun saveDailyCheckIn(checkIn: DailyCheckIn): DailyCheckIn fun getDailyCheckIns(habitId: String): Flow<List<DailyCheckIn>> }

package com.santiago.soberpath.domain.repository

import com.santiago.soberpath.domain.model.AppConfig
import kotlinx.coroutines.flow.Flow

interface ConfigRepository {
    fun getRemoteConfig(): Flow<AppConfig>
}

package com.santiago.soberpath.domain.repository
import com.santiago.soberpath.domain.model.Habit import com.santiago.soberpath.domain.model.Milestone import com.santiago.soberpath.domain.model.SobrietyProgress import java.time.LocalDate import kotlinx.coroutines.flow.Flow
interface HabitRepository { suspend fun createHabit(habit: Habit): Habit fun getActiveHabit(): Flow<Habit?> suspend fun registerRelapse(habitId: String, relapseDate: LocalDate): Habit? fun getSobrietyProgress(habitId: String): Flow<SobrietyProgress> fun getMilestones(habitId: String): Flow<List<Milestone>> }

package com.santiago.soberpath.domain.repository
import com.santiago.soberpath.domain.model.MotivationReason import kotlinx.coroutines.flow.Flow
interface MotivationRepository { suspend fun addMotivationReason(reason: MotivationReason): MotivationReason fun getMotivationReasons(habitId: String): Flow<List<MotivationReason>> }

package com.santiago.soberpath.domain.usecase

import com.santiago.soberpath.domain.model.MotivationReason
import com.santiago.soberpath.domain.repository.MotivationRepository

class AddMotivationReasonUseCase(
    private val motivationRepository: MotivationRepository
) {
    suspend operator fun invoke(reason: MotivationReason): MotivationReason {
        return motivationRepository.addMotivationReason(reason)
    }
}

package com.santiago.soberpath.domain.usecase

import com.santiago.soberpath.domain.model.Habit
import com.santiago.soberpath.domain.repository.HabitRepository

class CreateHabitUseCase(
    private val habitRepository: HabitRepository
) {
    suspend operator fun invoke(habit: Habit): Habit = habitRepository.createHabit(habit)
}

package com.santiago.soberpath.domain.usecase

import com.santiago.soberpath.domain.model.Habit
import com.santiago.soberpath.domain.repository.HabitRepository
import kotlinx.coroutines.flow.Flow

class GetActiveHabitUseCase(
    private val habitRepository: HabitRepository
) {
    operator fun invoke(): Flow<Habit?> = habitRepository.getActiveHabit()
}

package com.santiago.soberpath.domain.usecase

import com.santiago.soberpath.domain.model.DailyCheckIn
